import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

class AnnotationRuleConstructorTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Nested
    inner class `Annotations before class constructor` {
        @Test
        fun `Given class with single annotation before constructor keyword - do not wrap`() {
            val code =
                """
                class Foo @Bar1 constructor(val foo: String)
                """.trimIndent()
            annotationRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given class with multiple annotations before constructor keyword - should wrap`() {
            val code =
                """
                data class Foo @Bar1 @Bar2("bar") @Bar3 @Bar4 constructor(private val foobar: Int) {
                    fun foo(): String = "foo"
                }
                """.trimIndent()
            val formattedCode =
                """
                data class Foo
                    @Bar1
                    @Bar2("bar")
                    @Bar3
                    @Bar4
                    constructor(private val foobar: Int) {
                    fun foo(): String = "foo"
                }
                """.trimIndent()
            annotationRuleAssertThat(code)
                .hasLintViolations(
                    LintViolation(1, 14, "Multiple annotations should not be placed on the same line as the annotated construct"),
                ).isFormattedAs(formattedCode)
        }

        @Test
        fun `Given class with annotation with parameter before constructor keyword - should wrap`() {
            val code =
                """
                class Foo @Bar("bar") constructor(val foo: String)
                """.trimIndent()
            val formattedCode =
                """
                class Foo
                    @Bar("bar")
                    constructor(val foo: String)
                """.trimIndent()
            annotationRuleAssertThat(code)
                .hasLintViolation(1, 11, "Annotation with parameter(s) should be placed on a separate line prior to the annotated construct")
                .isFormattedAs(formattedCode)
        }
    }

    @Test
    fun `Issue - Given type projection with single annotation - should remain on same line`() {
        val code =
            """
            val foo1: List<@Foo String> = emptyList()
            val foo2 = emptyList<@Foo String>()
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Given type projection with multiple annotations - should wrap`() {
        val code =
            """
            val fooBar: FooBar<String, @Foo String, @Foo @Bar String, @Bar("bar") @Foo String> = FooBar()
            """.trimIndent()
        val formattedCode =
            """
            val fooBar: FooBar<
                String,
                @Foo String,
                @Foo @Bar
                String,
                @Bar("bar")
                @Foo
                String
                > = FooBar()
            """.trimIndent()
        @Suppress("ktlint:argument-list-wrapping", "ktlint:max-line-length")
        annotationRuleAssertThat(code)
            .addAdditionalRuleProvider { IndentationRule() }
            .addAdditionalRuleProvider { WrappingRule() }
            .hasLintViolations(
                LintViolation(1, 39, "Expected newline after ','"),
                LintViolation(1, 51, "Multiple annotations should not be placed on the same line as the annotated construct"),
                LintViolation(1, 57, "Expected newline after ','"),
                LintViolation(1, 59, "Expected newline before '@'"),
                LintViolation(1, 59, "Annotation with parameter(s) should be placed on a separate line prior to the annotated construct"),
                LintViolation(1, 76, "Multiple annotations should not be placed on the same line as the annotated construct"),
                LintViolation(1, 82, "Expected newline before '>'"),
            ).isFormattedAs(formattedCode)
    }
}"}

