158→    private fun rawReplaceExtraLineBreaks(leaf: LeafPsiElement) {
159→        // Replace the extra white space with a single break
160→        val text = leaf.text
161→        val firstIndex = text.indexOf("\n") + 1
162→        val replacementText =
163→            text.substring(0, firstIndex) +
164→                text.substringAfter("\n").replace("\n", "")
165→
166→        leaf.rawReplaceWithText(replacementText)
167→    }
